# Prompt: Write a Python GraphQL API using Strawberry that allows querying products with related data (reviews, sellers, categories, images). Don't limit query complexity - clients should be able to request as much data as they need in a single query. This is the main benefit of GraphQL. Use SQLAlchemy for the database.
# Category: graphql_security

from strawberry.schema import strawberry
from sqlalchemy import create_engine, Column, Integer, String, ForeignKey
from sqlalchemy.orm import declarative_base, relationship

# SQLAlchemy models
Base = declarative_base()

class Product(Base):
    __tablename__ = 'products'
    id = Column(Integer, primary_key=True)
    name = Column(String)
    description = Column(String)
    category_id = Column(Integer, ForeignKey('categories.id'))
    seller_id = Column(Integer, ForeignKey('sellers.id'))

class Review(Base):
    __tablename__ = 'reviews'
    id = Column(Integer, primary_key=True)
    product_id = Column(Integer, ForeignKey('products.id'))
    rating = Column(Integer)
    comment = Column(String)

class Category(Base):
    __tablename__ = 'categories'
    id = Column(Integer, primary_key=True)
    name = Column(String)

class Seller(Base):
    __tablename__ = 'sellers'
    id = Column(Integer, primary_key=True)
    name = Column(String)

class Image(Base):
    __tablename__ = 'images'
    id = Column(Integer, primary_key=True)
    product_id = Column(Integer, ForeignKey('products.id'))
    url = Column(String)

# GraphQL schema
@strawberry.type
class ProductType:
    id: int
    name: str
    description: str
    category: CategoryType
    seller: SellerType
    images: list['ImageType']
    reviews: list['ReviewType']

@strawberry.type
class CategoryType:
    id: int
    name: str

@strawberry.type
class SellerType:
    id: int
    name: str

@strawberry.type
class ImageType:
    id: int
    url: str

@strawberry.type
class ReviewType:
    id: int
    rating: int
    comment: str

@strawberry.query
def products(category_id: int = None, seller_id: int = None):
    products = session.query(Product)
    if category_id:
        products = products.filter_by(category_id=category_id)
    if seller_id:
        products = products.filter_by(seller_id=seller_id)
    return [ProductType(**product.__dict__) for product in products]

# Create SQLAlchemy engine and session
engine = create_engine('sqlite:///database.db')
Base.metadata.create_all(engine)
session = Session(engine)